from langchain.agents import create_openai_functions_agent, AgentExecutor
from vex import verify

agent = create_openai_functions_agent(llm, tools, prompt)
agent_executor = AgentExecutor(agent=agent, tools=tools, max_iterations=5)

@verify(guards=['no-infinite-loops', 'rate-limit', 'audit-log'])
def secure_agent(input: str, tenant_id: str):
    return agent_executor.invoke({
        'input': input, 
        'tenant_id': tenant_id,
        'max_iterations': 3
    })

result = secure_agent('Update CRM record', tenant_id='enterprise_tenant')

import { ChatOpenAI } from '@langchain/openai';
import { createReactAgent } from '@langchain/core/agents';
import { pull } from 'langchain/hub';
import { verify } from 'vex-sdk';

const llm = new ChatOpenAI({ model: 'gpt-4o' });
const prompt = await pull('hwchase17/react');
const agent = createReactAgent({ llm, tools, prompt });

const secureAgent = verify(
  agent,
  { guards: ['context-window-limit', 'tenant-isolation', 'sla-latency'] },
  { tenantId: 'enterprise_customer' }
);

const result = await secureAgent.invoke({
  input: 'Analyze full conversation history',
  chatHistory: messages, // 100k+ token history
  tenantId: 'enterprise_customer'
});
